parameters.jsCode:
// 1. Accedemos al texto que devuelve Gemini (dentro de content.parts)
const rawText = $input.first().json.content.parts[0].text;

// 2. Limpiamos el texto eliminando los bloques de markdown
const cleanJsonString = rawText.replace(/```json|```/g, "").trim();

try {
    // 3. Convertimos el texto a un objeto JSON real
    const aiResult = JSON.parse(cleanJsonString);

    // 4. Devolvemos la decisión y el análisis para que n8n los use
    return {
        should_notify: aiResult.decision.should_notify,
        target_branch: aiResult.decision.target_branch,
        priority: aiResult.decision.priority,
        template_id: aiResult.decision.template_id,
        email_body: aiResult.decision.email_body, // Añadimos el cuerpo del correo dinámico
        ai_justification: aiResult.analysis.justification,
        ai_incident_detected: aiResult.analysis.detected_incident
    };
} catch (error) {
    return {
        should_notify: false,
        target_branch: "NONE",
        error: "Error al parsear el resultado de la IA",
        raw_text: rawText
    };
}

